function norm(s: string): string {
  return s.toLowerCase().replace(/ё/g, "е").replace(/[^a-zа-я0-9]+/gi, "");
}

export function getProductDescription(name: string): ProductDescription | undefined {
  return byNorm[norm(name)];
}
